"use strict";(self.webpackChunkelodvk_github_io=self.webpackChunkelodvk_github_io||[]).push([[849],{6164:e=>{e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"osintSidebar":[{"type":"link","label":"Passive Reconnaissance","href":"/docs/OffSec/osint/passive-recon","docId":"OffSec/osint/passive-recon","unlisted":false},{"type":"link","label":"Discovering Email Addresses","href":"/docs/OffSec/osint/email-discovery","docId":"OffSec/osint/email-discovery","unlisted":false},{"type":"link","label":"Google Fu","href":"/docs/OffSec/osint/Google Fu","docId":"OffSec/osint/Google Fu","unlisted":false},{"type":"link","label":"Identifying Website Technologies","href":"/docs/OffSec/osint/Identifying Website Technologies","docId":"OffSec/osint/Identifying Website Technologies","unlisted":false},{"type":"link","label":"Search Engine Operators for OSINT","href":"/docs/OffSec/osint/search-engine-operators","docId":"OffSec/osint/search-engine-operators","unlisted":false},{"type":"link","label":"Sock Puppets","href":"/docs/OffSec/osint/sock-puppet","docId":"OffSec/osint/sock-puppet","unlisted":false}],"activedirectorySidebar":[{"type":"category","label":"01 - Initial Attack Vectors","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"LLMNR Poisioning","href":"/docs/OffSec/Active Directory/Initial Attack Vectors/llmnr-poisioning","docId":"OffSec/Active Directory/Initial Attack Vectors/llmnr-poisioning","unlisted":false},{"type":"link","label":"SMB Relay Attack","href":"/docs/OffSec/Active Directory/Initial Attack Vectors/smb-relay","docId":"OffSec/Active Directory/Initial Attack Vectors/smb-relay","unlisted":false},{"type":"link","label":"IPv6 DNS Takeover via mitm6","href":"/docs/OffSec/Active Directory/Initial Attack Vectors/mitm6","docId":"OffSec/Active Directory/Initial Attack Vectors/mitm6","unlisted":false}],"href":"/docs/category/01---initial-attack-vectors"},{"type":"category","label":"02 - Post-Compromise Enumeration","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Domain Enumeration with ldapdomaindump","href":"/docs/OffSec/Active Directory/Post-Compromise Enumeration/ldapdomaindump","docId":"OffSec/Active Directory/Post-Compromise Enumeration/ldapdomaindump","unlisted":false},{"type":"link","label":"Domain Enumeration with Bloodhound","href":"/docs/OffSec/Active Directory/Post-Compromise Enumeration/bloodhound","docId":"OffSec/Active Directory/Post-Compromise Enumeration/bloodhound","unlisted":false},{"type":"link","label":"Domain Enumeration with PingCastle","href":"/docs/OffSec/Active Directory/Post-Compromise Enumeration/pingcastle","docId":"OffSec/Active Directory/Post-Compromise Enumeration/pingcastle","unlisted":false}],"href":"/docs/category/02---post-compromise-enumeration"},{"type":"category","label":"03 - Post-Compromise Attacks","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Dumping & Cracking Hashes \ud83d\udd10","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/dumping & cracking hashes","docId":"OffSec/Active Directory/Post-Compromise Attacks/dumping & cracking hashes","unlisted":false},{"type":"link","label":"Kerberoasting \ud83d\udd25","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/kerberoasting","docId":"OffSec/Active Directory/Post-Compromise Attacks/kerberoasting","unlisted":false},{"type":"link","label":"Token Impersonation","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/token-impersonation","docId":"OffSec/Active Directory/Post-Compromise Attacks/token-impersonation","unlisted":false},{"type":"link","label":"LNK File Attacks","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/lnk-file-attacks","docId":"OffSec/Active Directory/Post-Compromise Attacks/lnk-file-attacks","unlisted":false},{"type":"link","label":"GPP & cPassword","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/gpp","docId":"OffSec/Active Directory/Post-Compromise Attacks/gpp","unlisted":false},{"type":"link","label":"Credential Dumping with Mimikatz","href":"/docs/OffSec/Active Directory/Post-Compromise Attacks/mimikatz-cred-dumping","docId":"OffSec/Active Directory/Post-Compromise Attacks/mimikatz-cred-dumping","unlisted":false}],"href":"/docs/category/03---post-compromise-attacks"},{"type":"category","label":"04 - We\'ve Compromised the Domain - Now What?","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Dumping the NTDS.dit","href":"/docs/OffSec/Active Directory/post domain compormise/dump-ntds.dit","docId":"OffSec/Active Directory/post domain compormise/dump-ntds.dit","unlisted":false},{"type":"link","label":"Golden Ticket","href":"/docs/OffSec/Active Directory/post domain compormise/golden-ticket","docId":"OffSec/Active Directory/post domain compormise/golden-ticket","unlisted":false}],"href":"/docs/category/04---weve-compromised-the-domain---now-what"}],"cheatsheetsSidebar":[{"type":"link","label":"01 - Network Enumeration with Nmap","href":"/docs/cheatsheets/nmap","docId":"cheatsheets/nmap","unlisted":false},{"type":"link","label":"DirBuster","href":"/docs/cheatsheets/dirbuster","docId":"cheatsheets/dirbuster","unlisted":false},{"type":"link","label":"Gobuster","href":"/docs/cheatsheets/gobuster","docId":"cheatsheets/gobuster","unlisted":false},{"type":"link","label":"intro","href":"/docs/cheatsheets/intro","docId":"cheatsheets/intro","unlisted":false},{"type":"link","label":"Nikto","href":"/docs/cheatsheets/nikto","docId":"cheatsheets/nikto","unlisted":false},{"type":"link","label":"Reverse Shell Cheatsheet (PNPT/OSCP)","href":"/docs/cheatsheets/revshell-cheatsheet","docId":"cheatsheets/revshell-cheatsheet","unlisted":false}],"adSidebar":[{"type":"link","label":"Intorduction","href":"/docs/active_directory/intro","docId":"active_directory/intro","unlisted":false},{"type":"category","label":"Kerberos","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Introduction","href":"/docs/active_directory/kerberos/intro","docId":"active_directory/kerberos/intro","unlisted":false},{"type":"link","label":"AS-REP Roasting","href":"/docs/active_directory/kerberos/as-rep-roasting","docId":"active_directory/kerberos/as-rep-roasting","unlisted":false},{"type":"link","label":"Kerberoasting","href":"/docs/active_directory/kerberos/kerberoasting","docId":"active_directory/kerberos/kerberoasting","unlisted":false},{"type":"link","label":"Golden Ticket","href":"/docs/active_directory/kerberos/golden-ticket-attack","docId":"active_directory/kerberos/golden-ticket-attack","unlisted":false},{"type":"link","label":"Resource Based Constrained Delegation","href":"/docs/active_directory/kerberos/rbcd","docId":"active_directory/kerberos/rbcd","unlisted":false},{"type":"link","label":"Silver Ticket","href":"/docs/active_directory/kerberos/silver-ticket-attack","docId":"active_directory/kerberos/silver-ticket-attack","unlisted":false},{"type":"link","label":"Unconstrained Delegation","href":"/docs/active_directory/kerberos/unconstrained-delegation","docId":"active_directory/kerberos/unconstrained-delegation","unlisted":false}]},{"type":"category","label":"adcs","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"ESC15","href":"/docs/active_directory/adcs/esc15","docId":"active_directory/adcs/esc15","unlisted":false}]}]},"docs":{"active_directory/adcs/esc15":{"id":"active_directory/adcs/esc15","title":"ESC15","description":"This vulnerability has been patched. https://msrc.microsoft.com/update-guide/vulnerability/CVE-2024-49019","sidebar":"adSidebar"},"active_directory/intro":{"id":"active_directory/intro","title":"Intorduction","description":"","sidebar":"adSidebar"},"active_directory/kerberos/as-rep-roasting":{"id":"active_directory/kerberos/as-rep-roasting","title":"AS-REP Roasting","description":"What is AS-REP Roasting?","sidebar":"adSidebar"},"active_directory/kerberos/golden-ticket-attack":{"id":"active_directory/kerberos/golden-ticket-attack","title":"Golden Ticket","description":"Attempting these techniques on systems you do not have explicit, authorized permission to test is illegal and unethical. Always operate within legal and ethical boundaries.","sidebar":"adSidebar"},"active_directory/kerberos/intro":{"id":"active_directory/kerberos/intro","title":"Introduction","description":"Kerberos is a ticket-based network authentication protocol developed by MIT for Project Athena. It uses strong cryptography to prove the identities of users and services in a networked environment. Windows Active Directory environments use Kerberos extensively for authenticating users and services.","sidebar":"adSidebar"},"active_directory/kerberos/kerberoasting":{"id":"active_directory/kerberos/kerberoasting","title":"Kerberoasting","description":"","sidebar":"adSidebar"},"active_directory/kerberos/rbcd":{"id":"active_directory/kerberos/rbcd","title":"Resource Based Constrained Delegation","description":"At its core, Resource-Based Constrained Delegation (RBCD) is a security feature in Windows Active Directory that allows a resource (like a file server or a web service) to control which other services can act on behalf of a user to access it. This is a more secure and flexible model than traditional constrained delegation.","sidebar":"adSidebar"},"active_directory/kerberos/silver-ticket-attack":{"id":"active_directory/kerberos/silver-ticket-attack","title":"Silver Ticket","description":"A silver ticket attack is a post-exploitation technique that allows an attacker to gain unauthorized access to a specific service on a particular machine within a Windows Active Directory domain. Unlike the more powerful golden ticket attack which targets the Kerberos Ticket Granting Ticket (TGT) for domain-wide compromise, the silver ticket attack focuses on forging a Kerberos Ticket Granting Service (TGS) ticket for a single service (like CIFS for file sharing, HTTP for web services, or MSSQL for databases) running on a specific server. This forged ticket enables the attacker to authenticate directly to that service, bypassing the need for a legitimate Kerberos authentication flow involving the Domain Controller (DC).","sidebar":"adSidebar"},"active_directory/kerberos/unconstrained-delegation":{"id":"active_directory/kerberos/unconstrained-delegation","title":"Unconstrained Delegation","description":"Unconstrained Delegation means, that an account is allowed to impersonate ANY user to ANY service. So from an attackers perspective this seems like a really valuable target to to get control over, as it most likely means game over.","sidebar":"adSidebar"},"cheatsheets/dirbuster":{"id":"cheatsheets/dirbuster","title":"DirBuster","description":"DirBuster is a multi-threaded Java application designed to brute-force directories and file names on web/application servers. It\u2019s particularly useful during penetration tests to uncover hidden paths and sensitive files.","sidebar":"cheatsheetsSidebar"},"cheatsheets/gobuster":{"id":"cheatsheets/gobuster","title":"Gobuster","description":"Gobuster is a fast and flexible command-line tool written in Go, used to brute-force:","sidebar":"cheatsheetsSidebar"},"cheatsheets/intro":{"id":"cheatsheets/intro","title":"intro","description":"","sidebar":"cheatsheetsSidebar"},"cheatsheets/nikto":{"id":"cheatsheets/nikto","title":"Nikto","description":"Nikto is an open-source web server scanner written in Perl. It is designed to identify potential vulnerabilities, misconfigurations, outdated software, and insecure files or scripts on web servers.","sidebar":"cheatsheetsSidebar"},"cheatsheets/nmap":{"id":"cheatsheets/nmap","title":"01 - Network Enumeration with Nmap","description":"Enumeration","sidebar":"cheatsheetsSidebar"},"cheatsheets/revshell-cheatsheet":{"id":"cheatsheets/revshell-cheatsheet","title":"Reverse Shell Cheatsheet (PNPT/OSCP)","description":"First, start a listener on your attacker machine to catch the incoming connection. Always start your listener first!","sidebar":"cheatsheetsSidebar"},"intro":{"id":"intro","title":"Intorduction","description":""},"OffSec/Active Directory/Initial Attack Vectors/llmnr-poisioning":{"id":"OffSec/Active Directory/Initial Attack Vectors/llmnr-poisioning","title":"LLMNR Poisioning","description":"So, you\'re a pentester. You\'ve landed on a client\'s internal network, your Kali terminal is glowing, and you\'re wondering, \\"What\'s the quickest way to get some credentials around here?\\" Before you start firing off complex exploits, let\'s talk about listening. Specifically, listening for the desperate, misguided cries of Windows machines that have lost their way.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Initial Attack Vectors/mitm6":{"id":"OffSec/Active Directory/Initial Attack Vectors/mitm6","title":"IPv6 DNS Takeover via mitm6","description":"You\'ve poisoned local name resolution with Responder and relayed credentials with ntlmrelayx. You feel like a true network ninja. But what if I told you there\'s a way to force clients to talk to you without waiting for a user to make a typo? What if you could become the network\'s DNS server just by asking nicely?","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Initial Attack Vectors/smb-relay":{"id":"OffSec/Active Directory/Initial Attack Vectors/smb-relay","title":"SMB Relay Attack","description":"Alright, so you\'ve mastered LLMNR & NBT-NS poisoning and you\u2019re swimming in NTLMv2 hashes. Cracking them is fun, but what if the user has a 25-character password generated by a password manager? You could spend the rest of the engagement turning your GPU into a space heater, or... you could just skip the cracking part entirely.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/post domain compormise/dump-ntds.dit":{"id":"OffSec/Active Directory/post domain compormise/dump-ntds.dit","title":"Dumping the NTDS.dit","description":"You\'ve done it. After hours of careful enumeration, privilege escalation, and lateral movement, you\'ve finally compromised a Domain Admin account. You have the run of the entire Active Directory domain. The war is won, right? Almost. Now it\'s time to secure the ultimate prize, the digital crown jewels of the kingdom: the NTDS.dit file.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/post domain compormise/golden-ticket":{"id":"OffSec/Active Directory/post domain compormise/golden-ticket","title":"Golden Ticket","description":"You\'ve dumped the krbtgt account credentials from a Domain Controller. You have its NTLM hash, but in a modern, secure Active Directory environment, that\'s only half the story. The true power lies in the stronger cryptographic keys derived from that password: the AES keys.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/dumping & cracking hashes":{"id":"OffSec/Active Directory/Post-Compromise Attacks/dumping & cracking hashes","title":"Dumping & Cracking Hashes \ud83d\udd10","description":"In the world of penetration testing, passwords are the ultimate prize. But you\'ll almost never find them stored in plaintext. Instead, you\'ll find their cryptographic shadows: hashes. A hash is a one-way mathematical function that turns a password into a fixed-length string of characters. While you can\'t reverse the math, if you can steal the hash, you can either use it directly (Pass the Hash) or try to find the original password.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/gpp":{"id":"OffSec/Active Directory/Post-Compromise Attacks/gpp","title":"GPP & cPassword","description":"Imagine a king who wanted to set the same password for the guards at every barracks in the kingdom. Instead of telling each guard individually, he wrote the password on a notice, locked it in a \\"secure\\" box using a key that everyone in the kingdom knew how to make, and then posted that notice in the public square for every guard to see. Sounds insane, right?","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/kerberoasting":{"id":"OffSec/Active Directory/Post-Compromise Attacks/kerberoasting","title":"Kerberoasting \ud83d\udd25","description":"So you\'ve landed in a target network, and you have a single, low-privilege domain user account. You can\'t dump hashes from the Domain Controller, and you don\'t have local admin anywhere. What do you do? Do you pack up and go home? No. You fire up the grill, because it\'s time for a Kerberoasting.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/lnk-file-attacks":{"id":"OffSec/Active Directory/Post-Compromise Attacks/lnk-file-attacks","title":"LNK File Attacks","description":"","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/mimikatz-cred-dumping":{"id":"OffSec/Active Directory/Post-Compromise Attacks/mimikatz-cred-dumping","title":"Credential Dumping with Mimikatz","description":"In the world of penetration testing, some tools are useful, some are powerful, and a select few are true legends. Mimikatz is in a league of its own. For years, it has been the single most feared and effective tool for post-exploitation on Windows systems. Its primary purpose? To pull passwords, hashes, and tickets directly from your computer\'s memory.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Attacks/token-impersonation":{"id":"OffSec/Active Directory/Post-Compromise Attacks/token-impersonation","title":"Token Impersonation","description":"You\'ve compromised a server. You have a shell, but you\'re running as a low-privilege service account like NT AUTHORITY\\\\NETWORK SERVICE. You run whoami /groups and see that you have a very interesting privilege: SeImpersonatePrivilege. Suddenly, your day just got a lot better.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Enumeration/bloodhound":{"id":"OffSec/Active Directory/Post-Compromise Enumeration/bloodhound","title":"Domain Enumeration with Bloodhound","description":"You\'ve landed your initial foothold and have a set of domain credentials. It\'s time to trade in your paper map for a GPS. BloodHound is that GPS. It doesn\'t just list domain objects; it maps the complex web of relationships between them, showing you the hidden paths and secret passages that lead directly to Domain Admin.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Enumeration/ldapdomaindump":{"id":"OffSec/Active Directory/Post-Compromise Enumeration/ldapdomaindump","title":"Domain Enumeration with ldapdomaindump","description":"So, you\'ve landed your initial foothold. You\'ve cracked a password from a Responder hash, or maybe you found some credentials on an internal web app. You now have a valid set of domain credentials\u2014username and password. What\'s next? Before you fire up BloodHound or start trying to Kerberoast, you need a quick, comprehensive lay of the land. You need a \\"phone book\\" of the entire domain.","sidebar":"activedirectorySidebar"},"OffSec/Active Directory/Post-Compromise Enumeration/pingcastle":{"id":"OffSec/Active Directory/Post-Compromise Enumeration/pingcastle","title":"Domain Enumeration with PingCastle","description":"You\'ve mapped the attack paths with BloodHound and read the kingdom\'s laws with Plumhound. But what if you could get an instant, high-level \\"security score\\" for the entire domain? What if a tool could automatically check for dozens of common misconfigurations and vulnerabilities and present them in a clean, prioritized report?","sidebar":"activedirectorySidebar"},"OffSec/Additional Active Directory Attacks/printnightmaire":{"id":"OffSec/Additional Active Directory Attacks/printnightmaire","title":"PrintNightmare (CVE-2021-1675)","description":"In the summer of 2021, another vulnerability took the security world by storm, proving once again that the most mundane services can harbor the most critical flaws. This was PrintNightmare (CVE-2021-34527, a variant of CVE-2021-1675), a flaw in the Windows Print Spooler service."},"OffSec/Additional Active Directory Attacks/zero-logon":{"id":"OffSec/Additional Active Directory Attacks/zero-logon","title":"ZeroLogon (CVE-2020-1472)","description":"Every so often, a vulnerability is discovered that is so critical, so easy to exploit, and so devastating that it sends shockwaves through the entire security industry. In 2020, that vulnerability was ZeroLogon (CVE-2020-1472)."},"OffSec/Exploitation Basics/brute-force-attacks":{"id":"OffSec/Exploitation Basics/brute-force-attacks","title":"A Detailed Guide to Hydra","description":"Hydra is a powerful and fast network logon cracker widely used in penetration testing to find weak passwords. It performs rapid dictionary attacks against more than 50 protocols, including Telnet, FTP, HTTP, HTTPS, SMB, and several databases."},"OffSec/Exploitation Basics/cred-stuffing-and-password-spraying":{"id":"OffSec/Exploitation Basics/cred-stuffing-and-password-spraying","title":"Credential Stuffing & Password Spraying","description":"Understanding how attackers automate password guessing is crucial for building secure applications. Two of the most common techniques are Credential Stuffing and Password Spraying. While they sound similar, their execution and purpose are distinct."},"OffSec/Exploitation Basics/Kioptrix":{"id":"OffSec/Exploitation Basics/Kioptrix","title":"Cracking Kioptrix Level 1","description":"This document provides a detailed walkthrough for the Kioptrix Level 1 boot-to-root challenge. We\'ll cover everything from initial reconnaissance to gaining root access, explaining each step along the way."},"OffSec/Exploitation Basics/payload-types":{"id":"OffSec/Exploitation Basics/payload-types","title":"Staged vs. Non-Staged Payloads","description":"Welcome, fellow red teamers and cybersecurity enthusiasts! You\u2019ve found your foothold, the exploit worked, and now it\'s time to drop your payload and open a shell. But what kind of payload do you choose? This single decision can be the difference between a successful, long-term engagement and a noisy, failed attempt that gets you caught in minutes."},"OffSec/Exploitation Basics/reversevsbindshell":{"id":"OffSec/Exploitation Basics/reversevsbindshell","title":"Reverse Shells vs Bind Shells","description":"In the world of penetration testing and red team operations, gaining remote access to a target system is a pivotal objective. Two fundamental techniques for achieving this are the reverse shell and the bind shell. Understanding the mechanics, advantages, and disadvantages of each is crucial for any aspiring cybersecurity professional, particularly for those pursuing red team certifications."},"OffSec/Find & Exploit Common Web Vulnerabilities/SQL Injection":{"id":"OffSec/Find & Exploit Common Web Vulnerabilities/SQL Injection","title":"SQL Injection: Making the Database Tell You Its Secrets \ud83e\udd2b","description":"Of all the vulnerabilities that plague web applications, few are as old, as devastating, or as consistently effective as SQL Injection (SQLi). It has been a member of the OWASP Top 10 list since its inception for a reason: it\'s a direct attack on the brain of an application\u2014its database."},"OffSec/intro":{"id":"OffSec/intro","title":"Intorduction","description":""},"OffSec/osint/email-discovery":{"id":"OffSec/osint/email-discovery","title":"Discovering Email Addresses","description":"Finding valid email addresses is a cornerstone of passive reconnaissance. It\'s the primary method for targeting individuals in phishing campaigns and can reveal usernames and company-wide email patterns. This guide covers the essential tools, websites, and techniques to uncover email addresses.","sidebar":"osintSidebar"},"OffSec/osint/Google Fu":{"id":"OffSec/osint/Google Fu","title":"Google Fu","description":"Google Fu (also known as Google Hacking or Google Dorking) is the skill of using Google\'s advanced search operators to find information that is not readily available through simple keyword searches. For a red teamer, it\'s one of the most powerful and essential passive reconnaissance techniques. You can uncover sensitive documents, login pages, vulnerable servers, and configuration files without ever sending a single packet to the target\'s systems.","sidebar":"osintSidebar"},"OffSec/osint/Identifying Website Technologies":{"id":"OffSec/osint/Identifying Website Technologies","title":"Identifying Website Technologies","description":"You can identify a website\'s technologies using browser extensions, online tools, and command-line scanners. These tools work by analyzing HTTP headers, source code, and directory structures to detect the frameworks, servers, and analytics services a site uses.","sidebar":"osintSidebar"},"OffSec/osint/passive-recon":{"id":"OffSec/osint/passive-recon","title":"Passive Reconnaissance","description":"Passive reconnaissance is the art of gathering intelligence about a target from publicly available sources without directly engaging or alerting them. The goal is to build a detailed operational picture before launching any active scanning or exploitation.","sidebar":"osintSidebar"},"OffSec/osint/search-engine-operators":{"id":"OffSec/osint/search-engine-operators","title":"Search Engine Operators for OSINT","description":"Search engine operators are specialized commands or symbols used to refine search queries, making them invaluable for Open-Source Intelligence (OSINT) tasks. These operators allow precise filtering, exclusion, or targeting of information, such as specific sites, file types, or proximity-based searches. Below is a detailed guide on operators for Google, Bing, Yandex, DuckDuckGo, and Baidu, tailored for OSINT purposes. Each section includes a table of key operators, their syntax, descriptions, and examples, based on official documentation and reliable sources.","sidebar":"osintSidebar"},"OffSec/osint/sock-puppet":{"id":"OffSec/osint/sock-puppet","title":"Sock Puppets","description":"In red-teaming and penetration testing, sock puppets are fictitious online personae used to mask the tester\u2019s real identity and simulate adversary social-engineering tactics. By blending seamlessly into target environments\u2014social media platforms, internal forums, or industry-specific networks\u2014they provide access to information and human responses that purely technical means cannot reach.","sidebar":"osintSidebar"},"OffSec/Post Exploitation/file-transfers-overview":{"id":"OffSec/Post Exploitation/file-transfers-overview","title":"Moving Tools and Loot Around the Network","description":"You\'ve gained your initial foothold on a target machine. You have a shell, but it\'s just a blank command prompt. Now what? Your favorite enumeration scripts, exploit tools, and binaries are all sitting back on your attacker machine. You need a way to get your tools onto the target to continue your attack, and later, you\'ll need a way to get the loot\u2014password hashes, sensitive documents\u2014off the target."},"OffSec/Post Exploitation/maintaining-access":{"id":"OffSec/Post Exploitation/maintaining-access","title":"Maintaining Access","description":"You\'ve done the hard part. You\'ve bypassed defenses, exploited a vulnerability, and gained a shell on a target system. But what happens if the user reboots the machine, your shell crashes, or a network hiccup cuts your connection? You\'re back to square one. This is why the next step is Persistence."},"OffSec/The Ethical Hacker Methodology/stages-of-ethical-hacking":{"id":"OffSec/The Ethical Hacker Methodology/stages-of-ethical-hacking","title":"The Five Stages of Ethical Hacking","description":"The five stages of ethical hacking provide a systematic framework that cybersecurity professionals use to conduct penetration tests and red team operations. This lifecycle ensures a thorough and organized approach to identifying and mitigating vulnerabilities."},"OffSec/Web Application Enumeration, Revisited/amass":{"id":"OffSec/Web Application Enumeration, Revisited/amass","title":"Finding Subdomains with Amass","description":"You\'ve run a quick scan with Assetfinder and have a decent list of subdomains. But you have that nagging feeling... what if there\'s more? What if there\'s a forgotten development server, an old UAT portal, or a misconfigured API gateway that the simple tools missed? When you need to be absolutely certain you\'ve mapped an organization\'s entire external footprint, you bring out the heavy artillery: OWASP Amass."},"OffSec/Web Application Enumeration, Revisited/assetfinder":{"id":"OffSec/Web Application Enumeration, Revisited/assetfinder","title":"Finding Subdomains with Assetfinder","description":"Every penetration test or bug bounty hunt begins with one crucial phase dev.example.com, api.example.com, vpn.example.com, old-portal.example.com. Finding these is the first step to finding vulnerabilities."},"OffSec/Web Application Enumeration, Revisited/gowitness":{"id":"OffSec/Web Application Enumeration, Revisited/gowitness","title":"Screenshotting Websites with GoWitness \ud83d\udcf8","description":"You\'ve run your enumeration tools like Amass and filtered for live web servers with Httpx. You\'re now staring at a text file with hundreds, maybe even thousands, of URLs. The problem is, you have no idea what these sites are. Which ones are important login portals for corporate apps? Which are default Apache \\"It works!\\" pages? And which are forgotten, vulnerable applications from 2012?"},"OffSec/Web Application Enumeration, Revisited/Httprobe":{"id":"OffSec/Web Application Enumeration, Revisited/Httprobe","title":"Finding Alive Domains with Httprobe","description":"You\'ve just run Amass or Assetfinder and you\'re feeling great. You have a text file with thousands of potential subdomains belonging to your target. But now what? Are they all web servers? Are any of them even online? A huge percentage of subdomains in a large list might be mail servers, SSH gateways, or simply dead DNS records from long-forgotten projects."},"OffSec/Web Application Enumeration, Revisited/sumrecon":{"id":"OffSec/Web Application Enumeration, Revisited/sumrecon","title":"Automating Recon with sumrecon \ud83e\udd16","description":"You\'ve learned the reconnaissance workflow: you run assetfinder, pipe it to httpx, save the output, then feed that into gowitness and nmap. While this toolchain is powerful, running each step manually is repetitive and time-consuming. On a real engagement, you want to spend your brainpower on finding vulnerabilities, not on babysitting your terminal."}}}}')}}]);